import './App.css';
import { Button } from './components/button';

function App() {

  const fetchprotein=()=>{
    fetch("http://localhost:8000").then(req=>req.json).then(data=>console.log(data));
  }

  return (
    <>
      <Button value={"Protein"}  func={fetchprotein} />
      <Button value={"Creatine"} func={fetchprotein} />
      <Button value={"Steroids"} function={fetchprotein} />
      <Button value={"Minerals"} function={fetchprotein} />
    </>
  );
}

export default App;
